import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useSocket } from '../context/SocketContext';
import axios from 'axios';
import './Dashboard.css';

function Dashboard() {
  const { user, logout, updateBalance } = useAuth();
  const { socket, isConnected } = useSocket();
  const navigate = useNavigate();
  const [rooms, setRooms] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [advertisement, setAdvertisement] = useState(null);
  const [balance, setBalance] = useState(user?.wallet_balance || 0);
  const [transactions, setTransactions] = useState([]);

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

  useEffect(() => {
    fetchRooms();
    fetchBalance();
    fetchAdvertisement();
  }, []);

  const fetchRooms = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${API_URL}/game/rooms`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      console.log('Rooms fetched:', response.data);
      setRooms(response.data.rooms || []);
    } catch (error) {
      console.error('Fetch rooms error:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchBalance = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get(`${API_URL}/wallet/balance`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      console.log('Balance fetched:', response.data);
      setBalance(response.data.balance);
      setTransactions(response.data.transactions || []);
      if (updateBalance) updateBalance(response.data.balance);
    } catch (error) {
      console.error('Fetch balance error:', error);
    }
  };

  const fetchAdvertisement = async () => {
    try {
      const response = await axios.get(`${API_URL}/admin/advertisement`);
      if (response.data.is_enabled) {
        setAdvertisement(response.data);
        setShowModal(true);
      }
    } catch (error) {
      console.error('Fetch advertisement error:', error);
    }
  };

  const joinRoom = async (roomId, entryFee) => {
    console.log('===== JOIN ROOM CLICKED =====');
    console.log('Room ID:', roomId);
    console.log('Entry Fee:', entryFee);
    console.log('Current balance:', balance);
    
    // Ask user for cartela count
    const userChoice = window.confirm('Choose number of cartelas:\n\n✅ Click OK for 1 cartela\n❌ Click Cancel for 2 cartelas');
    const cartelaCount = userChoice === false ? 2 : 1;
    
    const requiredAmount = entryFee * cartelaCount;
    console.log('Cartela count:', cartelaCount);
    console.log('Required amount:', requiredAmount);
    
    if (balance < requiredAmount) {
      alert(`❌ Insufficient balance!\n\nRequired: ${requiredAmount} Birr\nYour balance: ${balance} Birr\n\nPlease deposit to play.`);
      return;
    }
    
    setLoading(true);
    
    try {
      const token = localStorage.getItem('token');
      console.log('Sending join request...');
      
      const response = await axios.post(
        `${API_URL}/game/rooms/${roomId}/join`,
        { cartelaCount: cartelaCount },
        {
          headers: { 
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
          }
        }
      );
      
      console.log('Join response:', response.data);
      
      if (response.data.success) {
        console.log('Join successful! Navigating to game room...');
        // Navigate to game room
        navigate(`/game/${roomId}`, { 
          state: { 
            gameId: response.data.game.id,
            cartelas: response.data.cartelas,
            roomId: roomId,
            entryFee: entryFee
          } 
        });
      } else {
        alert(response.data.message || 'Failed to join room');
      }
    } catch (error) {
      console.error('Join error:', error);
      if (error.response) {
        alert(`❌ Server error: ${error.response.data.error || error.response.data.message || 'Unknown error'}`);
      } else if (error.request) {
        alert('❌ Cannot connect to server. Make sure backend is running.');
      } else {
        alert(`❌ Error: ${error.message}`);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const closeModal = () => {
    setShowModal(false);
  };

  if (loading && rooms.length === 0) {
    return (
      <div className="dashboard">
        <div className="loading-container">
          <div className="loader"></div>
          <p>Loading...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard">
      {/* Advertisement Modal */}
      {showModal && advertisement && (
        <div className="modal-overlay" onClick={closeModal}>
          <div className="modal-content glass-card" onClick={(e) => e.stopPropagation()}>
            <button className="modal-close" onClick={closeModal}>×</button>
            {advertisement.image_url && (
              <img src={advertisement.image_url} alt="Advertisement" className="modal-image" />
            )}
            <p className="modal-message">{advertisement.message}</p>
            <button className="btn-primary" onClick={closeModal}>Close</button>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="dashboard-header">
        <div className="header-content">
          <h1 className="casino-gold">🎰 BINGO GAME</h1>
          <div className="header-info">
            <div className="balance-card">
              <span>💰 Balance:</span>
              <strong>{balance} Birr</strong>
            </div>
            <div className="connection-status">
              {isConnected ? '🟢 Online' : '🔴 Offline'}
            </div>
            <button onClick={handleLogout} className="btn-logout">Logout</button>
          </div>
        </div>
      </header>

      {/* User Stats */}
      <div className="stats-container">
        <div className="stat-card glass-card">
          <div className="stat-icon">🎮</div>
          <div className="stat-info">
            <span>Games Played</span>
            <strong>{user?.total_games_played || 0}</strong>
          </div>
        </div>
        <div className="stat-card glass-card">
          <div className="stat-icon">🏆</div>
          <div className="stat-info">
            <span>Games Won</span>
            <strong>{user?.total_games_won || 0}</strong>
          </div>
        </div>
        <div className="stat-card glass-card">
          <div className="stat-icon">🎁</div>
          <div className="stat-info">
            <span>Bonus Won</span>
            <strong>{user?.total_bonus_won || 0} Birr</strong>
          </div>
        </div>
      </div>

      {/* Game Rooms */}
      <div className="rooms-container">
        <h2>Select Game Room</h2>
        {rooms.length === 0 ? (
          <div className="loading">No rooms available</div>
        ) : (
          <div className="rooms-grid">
            {rooms.map(room => (
              <div key={room.id} className="room-card glass-card">
                <h3>{room.name}</h3>
                <div className="room-details">
                  <p>Entry Fee: <strong>{room.entry_fee} Birr</strong></p>
                  <p>Current Players: <strong>{room.current_players || 0}</strong></p>
                  <p>Commission: <strong>{room.commission_percent}%</strong></p>
                </div>
                <button 
                  className="btn-primary"
                  onClick={() => joinRoom(room.id, room.entry_fee)}
                >
                  Join Room
                </button>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Deposit Info */}
      <div className="deposit-info glass-card">
        <h3>💰 Deposit Money</h3>
        <p>Send money to Telebirr:</p>
        <div className="telebirr-number">09XX-XXXXXX</div>
        <p className="deposit-note">
          After sending, click the button below to submit your transaction details
        </p>
        <button 
          className="btn-primary"
          onClick={() => alert('Deposit page coming soon!')}
        >
          Submit Deposit Request
        </button>
      </div>

      {/* Recent Transactions */}
      <div className="transactions-container glass-card">
        <h3>Recent Transactions</h3>
        <div className="transactions-list">
          {transactions.length === 0 ? (
            <p>No transactions yet</p>
          ) : (
            transactions.slice(0, 5).map(tx => (
              <div key={tx.id} className="transaction-item">
                <span>{new Date(tx.created_at).toLocaleString()}</span>
                <span className={`amount ${tx.amount > 0 ? 'positive' : 'negative'}`}>
                  {tx.amount > 0 ? '+' : ''}{tx.amount} Birr
                </span>
                <span className="type">{tx.type}</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
